"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[282],{3275:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":" \\nCreates a generic Group. \\nGroups manage collections of Entities (any instance with a position in the world like BaseParts, Models, Attachments, etc.) that Observers should track.\\n\\n```lua\\nlocal myGroup = Group.new({\\n\\tentities = { NPC1, NPC2, NPC3 }, -- Add entities\\n\\tautoClean = true, -- Entities in group are cleaned up when entities are destroyed\\n})\\n```","params":[{"name":"config","desc":"","lua_type":"{ entities: { T }?, autoClean: boolean? }?"}],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"static","tags":["Constructor"],"source":{"line":129,"path":"src/Classes/Group.luau"}},{"name":"fromTag","desc":" \\nCreates a dynamic Group that automatically tracks all instances with a specific tag.\\nInstances are only tracked while they are descendants of the Workspace.","params":[{"name":"tag","desc":"","lua_type":"string"}],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"static","tags":["Constructor"],"source":{"line":167,"path":"src/Classes/Group.luau"}},{"name":"players","desc":" \\nReturns a Group that automatically tracks all Players in the server.\\n\\n:::info Behavior\\n* Automatically tracks the `HumanoidRootPart` of every player.\\n* Handles `PlayerAdded` and `CharacterAdded` internally.\\n:::","params":[],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"static","tags":["Constructor"],"source":{"line":243,"path":"src/Classes/Group.luau"}},{"name":"localPlayer","desc":" \\nReturns a Group that tracks only the LocalPlayer.\\n\\n:::info Behavior\\n* Automatically tracks the `HumanoidRootPart` of the local player.\\n* Handles `CharacterAdded` internally.\\n:::","params":[],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"static","tags":["Constructor"],"realm":["Client"],"source":{"line":295,"path":"src/Classes/Group.luau"}},{"name":"setAutoClean","desc":" \\nEnables or disables automatic cleanup for Instances in this group.\\nWhen enabled, if an Instance is Destroyed() or parented to nil, it will be \\nautomatically removed from this group.","params":[{"name":"enabled","desc":"","lua_type":"boolean"}],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"method","source":{"line":323,"path":"src/Classes/Group.luau"}},{"name":"add","desc":" \\nAdds an entity to the group. If the entity is already in another group, \\nit is automatically removed from the old one first.\\n\\n#### Example: Adding Different Entity Types\\n```lua\\n-- Adding a BasePart and a Model\\nmyGroup:add(workspace.Part):add(workspace.NPCModel)\\n\\n-- Adding a custom table\\nlocal spell = {\\n\\tCFrame = CFrame.new(0, 10, 0),\\n\\tName = \'Fireball\'\\n}\\nmyGroup:add(spell)\\n```\\n\\n:::info Strategy Detection\\nQuickZone automatically determines how to track the entity\'s position:\\n* **BasePart:** Uses `Position`\\n* **Model:** Uses `PrimaryPart.Position` or `GetPivot()`\\n* **Attachment/Bone:** Uses `WorldPosition`\\n* **Camera:** Uses `CFrame`\\n* **Table:** Looks for `.Position`, `.CFrame`, `.WorldPosition`, or `:GetPivot()`.\\n:::","params":[{"name":"entity","desc":"The object to track.","lua_type":"any"}],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"method","source":{"line":387,"path":"src/Classes/Group.luau"}},{"name":"addBulk","desc":" \\nAdds multiple entities to the group.\\n\\n```lua\\n-- Add an entire folder of NPCs at once\\nmyGroup:addBulk(workspace.Enemies:GetChildren())\\n```","params":[{"name":"entities","desc":"Array of entities to add.","lua_type":"{ any }"}],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"method","source":{"line":408,"path":"src/Classes/Group.luau"}},{"name":"remove","desc":" \\nRemoves the entity from the group.","params":[{"name":"entity","desc":"","lua_type":"any"}],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"method","source":{"line":424,"path":"src/Classes/Group.luau"}},{"name":"removeBulk","desc":" \\nRemoves multiple entities from the group.","params":[{"name":"entities","desc":"","lua_type":"{ any }"}],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"method","source":{"line":440,"path":"src/Classes/Group.luau"}},{"name":"clear","desc":" \\nRemoves all entities from the group.\\nThis fires \'onExit\' events for every entity currently inside a zone.","params":[],"returns":[{"desc":"","lua_type":"Group"}],"function_type":"method","source":{"line":456,"path":"src/Classes/Group.luau"}},{"name":"contains","desc":" \\nChecks if a specific entity is currently a member of this group.","params":[{"name":"entity","desc":"","lua_type":"any"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":472,"path":"src/Classes/Group.luau"}},{"name":"getId","desc":" \\nReturns the unique internal ID of the group.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":485,"path":"src/Classes/Group.luau"}},{"name":"getEntities","desc":" \\nReturns a list of all entities currently belonging to the group.","params":[],"returns":[{"desc":"","lua_type":"{ any }"}],"function_type":"method","source":{"line":496,"path":"src/Classes/Group.luau"}},{"name":"getPlayers","desc":" \\nReturns a list of all Players currently represented in the group.","params":[],"returns":[{"desc":"","lua_type":"{ Player }"}],"function_type":"method","source":{"line":511,"path":"src/Classes/Group.luau"}},{"name":"iterEntities","desc":" \\nIterates over all entities currently belonging to the group.\\nProvides a zero-allocation way to loop through entities, ideal for high-frequency \\nchecks.\\n\\n```lua\\nfor entity in myGroup:iterEntities() do\\n\\tprint(entity.Name .. \\" is in the group!\\")\\nend\\n```","params":[],"returns":[{"desc":"","lua_type":"() -> any?"}],"function_type":"method","source":{"line":537,"path":"src/Classes/Group.luau"}},{"name":"iterPlayers","desc":" \\nIterates over all players currently represented in the group.","params":[],"returns":[{"desc":"","lua_type":"() -> Player?"}],"function_type":"method","source":{"line":556,"path":"src/Classes/Group.luau"}},{"name":"onDestroy","desc":" \\nFires when `destroy()` is called on the group.\\n\\n```lua\\nlocal disconnect = myGroup:onDestroy(function()\\n\\tprint(\'Group was destroyed!\')\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"() -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":590,"path":"src/Classes/Group.luau"}},{"name":"destroy","desc":" \\nCleans up the group, removes all tracked entities, and detaches any \\nassociated observers.","params":[],"returns":[],"function_type":"method","tags":["Destructor"],"source":{"line":613,"path":"src/Classes/Group.luau"}}],"properties":[],"types":[],"name":"Group","desc":" \\nGroups represent a collection of entities that should be tracked by the system.\\n\\n:::info Observer\\nEvery entity must be in a group to be observed.\\n:::","source":{"line":111,"path":"src/Classes/Group.luau"}}')}}]);